const payload = $json || {};
const callback = payload.callback_query || {};
const callbackData = callback.data || '';

if (!callbackData.startsWith('COUNCIL_')) {
  return [];
}

const [rawDecision, sessionId] = callbackData.split('::');
const chatId = String(callback?.message?.chat?.id || '');
const allowedChatId = String($vars.SALEH_TELEGRAM_CHAT_ID || '');

if (!allowedChatId || chatId !== allowedChatId) {
  return [{ json: { chatId, message: '⛔ هذا القرار غير مصرح لك. الاعتماد محصور بصالح فقط.' } }];
}

const map = {
  COUNCIL_APPROVE: { status: 'approved', label: 'اعتماد عبر تيليجرام' },
  COUNCIL_REJECT: { status: 'rejected', label: 'رفض عبر تيليجرام' },
  COUNCIL_RESTUDY: { status: 'restudy', label: 'إعادة دراسة عبر تيليجرام' },
};

const decisionInfo = map[rawDecision] || { status: 'awaiting_approval', label: 'قرار غير معروف' };

const fs = require('fs');
const logPath = '/app/logs/advisory_council_sessions.jsonl';

let updated = false;
let updatedRecord = null;

try {
  const content = fs.existsSync(logPath) ? fs.readFileSync(logPath, 'utf8') : '';
  const lines = content.split('\n').filter(Boolean);
  const rows = lines.map(line => {
    try {
      return JSON.parse(line);
    } catch {
      return null;
    }
  }).filter(Boolean);

  for (const row of rows) {
    if (String(row.sessionId) === String(sessionId)) {
      row.status = decisionInfo.status;
      row.dashboard_decision = decisionInfo.label;
      row.decision_source = 'telegram';
      row.decision_updated_at = new Date().toISOString();
      row.decision_notes = `Telegram callback: ${rawDecision}`;
      updated = true;
      updatedRecord = row;
      break;
    }
  }

  fs.writeFileSync(logPath, rows.map(r => JSON.stringify(r)).join('\n') + (rows.length ? '\n' : ''), 'utf8');
} catch (error) {
  return [{ json: { chatId, message: `❌ تعذر تحديث السجل: ${error.message}` } }];
}

if (!updated) {
  return [{ json: { chatId, message: `⚠️ لم يتم العثور على جلسة بهذا المعرف: ${sessionId}` } }];
}

const statusText = decisionInfo.status === 'approved'
  ? '✅ تم اعتماد توصية المجلس'
  : decisionInfo.status === 'rejected'
    ? '❌ تم رفض توصية المجلس'
    : '🔄 تم طلب إعادة دراسة من المجلس';

const topic = updatedRecord?.topic || 'بدون عنوان';

return [{
  json: {
    chatId,
    message: `${statusText}\n\n🔖 الجلسة: ${sessionId}\n📋 الموضوع: ${topic}\n🕒 ${new Date().toLocaleString('ar-SA', { timeZone: 'Asia/Riyadh' })}`
  }
}];
